components.styles:
.card-custom {
  background: "rgba(255, 255, 255, 0.03)";
  border: "1px solid rgba(212, 175, 55, 0.15)";
  border-radius: "12px";
  padding: "1.5rem";
  transition: "all 0.3s ease";
  color: "#f8fafc";
}
.card-custom:hover {
  border-color: "#d4af37";
  transform: "translateY(-4px)";
  box-shadow: "0 10px 20px rgba(212, 175, 55, 0.1)";
}
.gold-badge {
  background: "rgba(212, 175, 55, 0.1)";
  color: "#d4af37";
  padding: "0.25rem 0.75rem";
  border-radius: "50px";
  font-size: "0.85rem";
  font-weight: "bold";
}
.card-header {
  display: flex; flex-direction: row; align-items: center;
  justify-content: space-between;
  align-items: center;
  margin-bottom: "1rem";
}
.card-body {
  display: flex; flex-direction: column;
  gap: "0.5rem";
  font-size: "0.95rem";
  color: "#94a3b8";
}
.revenue-label {
  font-size: "0.85rem";
  color: "#64748b";
  margin-top: "0.5rem";
}
.revenue-value {
  font-size: "1.2rem";
  font-weight: "bold";
  color: "#10b981";
}

.lead-card-custom {
  background: "rgba(255, 255, 255, 0.02)";
  border: "1px solid rgba(255, 255, 255, 0.08)";
  border-radius: "12px";
  padding: "1.5rem";
  transition: "all 0.3s ease";
  color: "#f8fafc";
}
.lead-card-custom:hover {
  border-color: "#d4af37";
  transform: "translateY(-4px)";
  box-shadow: "0 10px 20px rgba(212, 175, 55, 0.05)";
}
.status-new {
  background: "rgba(59, 130, 246, 0.15)";
  color: "#3b82f6";
  padding: "0.25rem 0.5rem";
  border-radius: "4px";
  font-size: "0.8rem";
}
.status-in_progress {
  background: "rgba(245, 158, 11, 0.15)";
  color: "#f59e0b";
  padding: "0.25rem 0.5rem";
  border-radius: "4px";
  font-size: "0.8rem";
}
.status-won {
  background: "rgba(16, 185, 129, 0.15)";
  color: "#10b981";
  padding: "0.25rem 0.5rem";
  border-radius: "4px";
  font-size: "0.8rem";
}
.status-lost {
  background: "rgba(239, 68, 68, 0.15)";
  color: "#ef4444";
  padding: "0.25rem 0.5rem";
  border-radius: "4px";
  font-size: "0.8rem";
}
.lead-header {
  display: flex; flex-direction: row; align-items: center;
  justify-content: space-between;
  align-items: center;
  margin-bottom: "1rem";
}
.lead-value {
  font-size: "1.1rem";
  font-weight: "bold";
  color: "#d4af37";
}
